import{_ as t,o,c as a,a2 as r}from"./chunks/framework.Crpw6aS5.js";const p=JSON.parse('{"title":"市场时机","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-scene/市场时机.md","filePath":"05_quotes/by-scene/市场时机.md"}'),c={name:"05_quotes/by-scene/市场时机.md"};function u(l,e,q,s,h,n){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="市场时机" tabindex="-1">市场时机 <a class="header-anchor" href="#市场时机" aria-label="Permalink to &quot;市场时机&quot;">​</a></h1><blockquote><p>&quot;市场短期是投票机，长期是称重机。关注短期价格波动的人注定是输家。&quot;——巴菲特</p></blockquote><hr><h2 id="核心金句" tabindex="-1">核心金句 <a class="header-anchor" href="#核心金句" aria-label="Permalink to &quot;核心金句&quot;">​</a></h2><blockquote><p>&quot;在别人贪婪时恐惧，在别人恐惧时贪婪。说起来容易，做起来需要勇气。&quot;</p></blockquote><blockquote><p>&quot;我们从不对宏观经济做预测，也不对市场短期走势做预测。我们关注的是企业的长期价值。&quot;</p></blockquote><blockquote><p>&quot;1974年，当整个市场都在恐慌时，我说这是投资的最好时机。大多数人觉得我疯了。一年后市场大涨。&quot;</p></blockquote><blockquote><p>&quot;试图选择市场时机是愚蠢的。真正的问题是：你愿意在这只股票上持有十年吗？如果答案是肯定的，买入时机永远都是对的。&quot;</p></blockquote><blockquote><p>&quot;市场是为投资者服务的，不是为指导的。我们不试图从市场的短期波动中获利。&quot;</p></blockquote><hr><h2 id="相关主题" tabindex="-1">相关主题 <a class="header-anchor" href="#相关主题" aria-label="Permalink to &quot;相关主题&quot;">​</a></h2><p><a href="/search.html?q=逆向思维">逆向思维</a> · <a href="/search.html?q=长期主义">长期主义</a> · <a href="/search.html?q=风险">风险</a> · <a href="/search.html?q=内在价值">内在价值</a></p>',12)])])}const i=t(c,[["render",u]]);export{p as __pageData,i as default};
